/* BTItem — generic list item / row display molecule.
 * Figma: node 2056-48.
 * Shared between Vue (BTItem.vue) and React (BTItem.tsx) — one file, zero duplication.
 */

/* ── Root container ─────────────────────────────────────────────────────────── */

.bt-item {
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: var(--space-sm);
}

.bt-item--outline {
  border: 1px solid var(--border-primary);
  padding: var(--space-sm);
  border-radius: var(--radius-sm);
}

.bt-item--muted {
  background: var(--bg-subtle);
  padding: var(--space-sm);
  border-radius: var(--radius-sm);
}

/* ── Left area ──────────────────────────────────────────────────────────────── */

.bt-item__left {
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: var(--space-sm);
  flex: 1;
  min-width: 0;
}

.bt-item__left-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
}

.bt-item__left-icon > svg,
.bt-item__right-icon > svg {
  width: 16px;
  height: 16px;
  display: block;
}

/* Wrapper for any left-media element (network image, asset, SVG, etc.) */
.bt-item__media {
  flex-shrink: 0;
  width: 32px;
  height: 32px;
  border-radius: var(--radius-sm);
  overflow: hidden;          /* clips child to border-radius */
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.bt-item__media > img,
.bt-item__media > * {
  width: 100%;
  height: 100%;
  display: block;
  object-fit: cover;
}

/* ── Label stack ────────────────────────────────────────────────────────────── */

.bt-item__label {
  display: flex;
  flex-direction: column;
  gap: var(--space-2xs);
  min-width: 0;
  flex: 1;
}

.bt-item__title {
  font-size: var(--typography-font-size-sm);
  font-weight: 700;
  color: var(--text-primary);
  line-height: var(--typography-line-height-xs);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.bt-item__description {
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  color: var(--text-secondary);
  line-height: var(--typography-line-height-xs);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* ── Right area ─────────────────────────────────────────────────────────────── */

.bt-item__right {
  display: inline-flex;
  align-items: center;
  gap: var(--space-sm);
  flex-shrink: 0;
}

.bt-item__right-label {
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  color: var(--text-secondary);
  white-space: nowrap;
}

.bt-item__right-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
}

/**
 * BTItem — generic list item / row display molecule (React).
 * Figma: node 2056-48.
 *
 * Three container types: default (no chrome), outline, muted.
 * Optional left media: leftIcon node, BTAvatar, or image.
 * Optional right content: label text, BTButton outline-small, rightIcon node.
 *
 * @example Default with avatar
 * ```tsx
 * <BTItem
 *   title="Faisal Lestari"
 *   description="Software Engineer"
 *   leftAvatar={{ name: 'Faisal Lestari', color: 'blue' }}
 *   rightLabel="Admin"
 * />
 * ```
 *
 * @example Outline with button
 * ```tsx
 * <BTItem
 *   type="outline"
 *   title="Design Token Package"
 *   description="v2.3.1 — 4 changes"
 *   rightButton="View"
 *   onButtonClick={handleView}
 * />
 * ```
 */
import './BTItem.css';
import * as React from 'react';
import type { ReactNode } from 'react';
import type { BTItemProps } from './BTItem.types.js';
import { BTAvatar } from '../Avatar/BTAvatar.js';
import { BTButton } from '../../atoms/Button/BTButton.js';

export function BTItem({
  title,
  description,
  type = 'default',
  leftAvatar,
  leftImage,
  leftIcon,
  rightLabel,
  rightButton,
  rightIcon,
  onButtonClick,
}: BTItemProps & { leftImage?: ReactNode }) {
  const hasRight = rightButton != null || rightLabel != null || rightIcon != null;

  return (
    <div
      className={[
        'bt-item',
        type === 'outline' ? 'bt-item--outline' : '',
        type === 'muted'   ? 'bt-item--muted'   : '',
      ].filter(Boolean).join(' ')}
    >
      {/* Left area: media + label stack */}
      <div className="bt-item__left">
        {/* Avatar (highest precedence left media) */}
        {leftAvatar != null && (
          <BTAvatar item={leftAvatar} size="sm" />
        )}

        {/* Image slot — any element (network img, asset, SVG…) wrapped at 32×32 */}
        {leftAvatar == null && leftImage != null && (
          <span className="bt-item__media">{leftImage}</span>
        )}

        {/* Icon node (lowest left media precedence) */}
        {leftAvatar == null && leftImage == null && leftIcon != null && (
          <span className="bt-item__left-icon">{leftIcon}</span>
        )}

        {/* Title + description */}
        <span className="bt-item__label">
          <span className="bt-item__title">{title}</span>
          {description != null && (
            <span className="bt-item__description">{description}</span>
          )}
        </span>
      </div>

      {/* Right area */}
      {hasRight && (
        <div className="bt-item__right">
          {/* Button (takes precedence over label) */}
          {rightButton != null ? (
            <BTButton
              label={rightButton}
              variant="outline"
              size="small"
              onClick={onButtonClick}
            />
          ) : rightLabel != null ? (
            <span className="bt-item__right-label">{rightLabel}</span>
          ) : null}

          {/* Right icon */}
          {rightIcon != null && (
            <span className="bt-item__right-icon">{rightIcon}</span>
          )}
        </div>
      )}
    </div>
  );
}

BTItem.displayName = 'BTItem';

/**
 * BTItem — generic list item / row display molecule.
 * Figma: node 2056-48.
 *
 * Three container variants (default / outline / muted) with optional
 * left media (icon slot, avatar, image) and optional right content
 * (label, button, icon slot).
 */
import type { BTAvatarItem } from '../Avatar/BTAvatar.types';

export type BTItemType = 'default' | 'outline' | 'muted';

export interface BTItemProps {
  /** Main title text. Required. */
  title: string;
  /** Optional subtitle / description text below the title. */
  description?: string;
  /** Container style variant. @default 'default' */
  type?: BTItemType;
  /** Avatar payload — renders BTAvatar size="sm" (32px) on the left. */
  leftAvatar?: BTAvatarItem;
  /** Image URL — renders 32×32 rounded image on the left. */
  leftImage?: string;
  /** Right side text label (text-secondary, 12px). Ignored when rightButton is set. */
  rightLabel?: string;
  /** Right side button label — renders BTButton outline small. Takes precedence over rightLabel. */
  rightButton?: string;
  /** 16×16 icon element rendered on the left (lowest left media precedence). */
  leftIcon?: React.ReactNode;
  /** 16×16 icon element rendered on the right side. */
  rightIcon?: React.ReactNode;
  /** Called when the right button is clicked. */
  onButtonClick?: () => void;
}
